// // This module inverts the least significant bit (LSB) of a 4-bit binary input while keeping the most significant bits unchanged.
module top_module(
    input [3:0] i_binary,
    output reg [3:0] o_inverted
    );always @(*) begin
        o_inverted = {~i_binary[3], i_binary[2:0]};
    end

endmodule
